import{_ as l,o as t,c as a,ag as e}from"./chunks/framework.Cqf6AMW8.js";const _=JSON.parse('{"title":"CSS 三大特性","description":"CSS 三大特性相关知识，包括层叠性、继承性和优先级。","frontmatter":{"title":"CSS 三大特性","description":"CSS 三大特性相关知识，包括层叠性、继承性和优先级。","date":"2026-04-21T00:00:00.000Z","tags":["CSS","三大特性"],"sidebar":"auto"},"headers":[],"relativePath":"docs/frontend/css/CSS-基础-23-CSS三大特性.md","filePath":"docs/frontend/css/CSS-基础-23-CSS三大特性.md","lastUpdated":1776715536000}'),o={name:"docs/frontend/css/CSS-基础-23-CSS三大特性.md"};function r(s,i,n,d,p,S){return t(),a("div",null,[...i[0]||(i[0]=[e('<p>#CSS理论</p><p>======================================================</p><h2 id="css三大特性" tabindex="-1">CSS三大特性 <a class="header-anchor" href="#css三大特性" aria-label="Permalink to &quot;CSS三大特性&quot;">​</a></h2><h3 id="_1-层叠性" tabindex="-1">1. 层叠性 <a class="header-anchor" href="#_1-层叠性" aria-label="Permalink to &quot;1. 层叠性&quot;">​</a></h3><ul><li><p><strong>就近原则</strong>：距离元素最近的样式规则会覆盖较远的规则</p></li><li><p><strong>相同权重</strong>：后声明的样式会覆盖先声明的样式</p></li><li><p><strong>部分覆盖</strong>：只有冲突的属性会被覆盖</p></li></ul><h3 id="_2-继承性" tabindex="-1">2. 继承性 <a class="header-anchor" href="#_2-继承性" aria-label="Permalink to &quot;2. 继承性&quot;">​</a></h3><ul><li><p><strong>可继承的属性</strong>：</p><ul><li>文本相关：color、font-<em>、text-</em>、line-height</li><li>列表相关：list-style-*</li><li>其他：visibility、cursor</li></ul></li><li><p><strong>不可继承的属性</strong>：</p><ul><li>布局相关：width、height、margin、padding、border、display</li><li>背景相关：background-*</li><li>其他：z-index、opacity、box-shadow</li></ul></li></ul><h3 id="_3-优先级" tabindex="-1">3. 优先级 <a class="header-anchor" href="#_3-优先级" aria-label="Permalink to &quot;3. 优先级&quot;">​</a></h3><ul><li><p><strong>优先级从高到低</strong>：</p><ol><li>!important</li><li>内联样式</li><li>ID选择器</li><li>类选择器、伪类选择器、属性选择器</li><li>标签选择器、伪元素选择器</li><li>通用选择器、后代选择器、兄弟选择器</li></ol></li><li><p><strong>注意</strong>：继承的样式优先级最低</p></li></ul><p>======================================================</p>',10)])])}const h=l(o,[["render",r]]);export{_ as __pageData,h as default};
